/* BTCircleChart — custom-SVG pie / donut / donutRounded */

.bt-circle-chart {
  position: relative;
  display: inline-block;
}

.bt-circle-chart__svg {
  display: block;
  overflow: visible;
}

/* Entrance — badge labels + connector lines fade in alongside the clockwise
   segment sweep (the sweep itself is driven in JS via the geometry reveal). */
.bt-circle-chart__labels,
.bt-circle-chart__connector-line {
  animation: bt-circle-chart-fade 600ms ease-out both;
}

@keyframes bt-circle-chart-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@media (prefers-reduced-motion: reduce) {
  .bt-circle-chart__labels,
  .bt-circle-chart__connector-line {
    animation: none;
  }
}

/* Segment group — pops outward along its mid-angle when active. */
.bt-circle-chart__segment {
  cursor: pointer;
  transform-box: fill-box;
  transform-origin: center;
  transition: transform 120ms ease-out;
}

/* Arc stroke is the hit area; wedge fill is hittable by default. */
.bt-circle-chart__segment path {
  pointer-events: visiblePainted;
}

/* Connector lines (ring edge → badge). */
.bt-circle-chart__connector-line {
  stroke: var(--border-primary);
  stroke-width: 1;
  fill: none;
  pointer-events: none;
}

/* External badge labels overlay. */
.bt-circle-chart__labels {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.bt-circle-chart__badge {
  position: absolute;
  display: flex;
  flex-direction: column;
  align-items: center;
  transform: translate(-50%, -50%);
  text-align: center;
  line-height: 1.4;
}

.bt-circle-chart__badge-label {
  font-size: var(--typography-font-size-2xs);
  font-weight: 500;
  color: var(--text-secondary);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

.bt-circle-chart__badge-value {
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  color: var(--text-primary);
  font-family: var(--typography-font-family-sans, "Geist", system-ui);
}

/* Tooltip anchor — a 0×0 point on the ring the BTTooltip attaches to. */
.bt-circle-chart__tip {
  position: absolute;
  width: 0;
  height: 0;
  pointer-events: none;
}

.bt-circle-chart__tip-anchor {
  display: block;
  width: 0;
  height: 0;
}

/**
 * BTCircleChart — pie / donut / donutRounded chart molecule (custom SVG).
 *
 * Figma node 3404:1813 · M - CircleChart
 *
 * Rendered as raw SVG (no ApexCharts) so the web chart mirrors the Flutter
 * widget exactly: hovering (mouse) or tapping (touch) a segment pops it
 * outward and shows a floating BTTooltip, while every segment keeps a radial
 * leader line to its external Label + % badge. Geometry lives in
 * `internal/circle-chart.utils.ts` (shared verbatim with Vue).
 *
 * @example
 * ```tsx
 * <BTCircleChart sections={sections} variant="donut" />
 * ```
 */
import './BTCircleChart.css';
import { useEffect, useMemo, useState } from 'react';
import type { BTCircleSection, BTCircleChartVariant } from './BTCircleChart.types';
import { buildCircleGeometry } from './internal/circle-chart.utils';
import { BTTooltip } from '../tooltip/BTTooltip';

/** Clockwise entrance sweep duration (ms). */
const ENTER_DURATION = 700;

export interface BTCircleChartProps {
  sections: BTCircleSection[];
  variant?: BTCircleChartVariant;
  /** Width/height in px */
  size?: number;
}

export function BTCircleChart({
  sections,
  variant = 'pie',
  size = 208,
}: BTCircleChartProps) {
  /**
   * Clockwise entrance sweep (0..1). Tweened from 0→1 once on mount so the
   * chart draws itself in from 12 o'clock, mirroring the Recharts pie.
   */
  const [reveal, setReveal] = useState(0);

  useEffect(() => {
    const prefersReduced =
      typeof window !== 'undefined' &&
      window.matchMedia?.('(prefers-reduced-motion: reduce)').matches;
    if (prefersReduced) {
      setReveal(1);
      return;
    }
    let raf = 0;
    let start = 0;
    const tick = (now: number) => {
      if (!start) start = now;
      const p = Math.min(1, (now - start) / ENTER_DURATION);
      // easeOutCubic
      setReveal(1 - Math.pow(1 - p, 3));
      if (p < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, []);

  const geometry = useMemo(
    () => buildCircleGeometry(sections, size, variant, reveal),
    [sections, size, variant, reveal],
  );

  /** Index of the hovered / pressed segment, or -1 for none. */
  const [activeIndex, setActiveIndex] = useState(-1);

  const activeSegment =
    activeIndex >= 0 ? geometry.segments[activeIndex] ?? null : null;

  return (
    <div
      className="bt-circle-chart"
      style={{ width: size, height: size }}
      onPointerLeave={() => setActiveIndex(-1)}
    >
      <svg
        className="bt-circle-chart__svg"
        width={size}
        height={size}
        viewBox={`0 0 ${size} ${size}`}
      >
        {/* Radial connector lines (ring edge → badge), always visible. */}
        {geometry.segments.map((seg) => (
          <line
            key={`line-${seg.index}`}
            x1={seg.badge.lx1}
            y1={seg.badge.ly1}
            x2={seg.badge.lx2}
            y2={seg.badge.ly2}
            className="bt-circle-chart__connector-line"
          />
        ))}

        {/* Segments: filled wedge (pie) or stroked arc (donut/donutRounded). */}
        {geometry.segments.map((seg) => (
          <g
            key={`seg-${seg.index}`}
            className={`bt-circle-chart__segment${seg.index === activeIndex ? ' is-active' : ''}`}
            style={
              seg.index === activeIndex
                ? { transform: `translate(${seg.popDx}px, ${seg.popDy}px)` }
                : undefined
            }
            onPointerEnter={() => setActiveIndex(seg.index)}
            onPointerDown={() => setActiveIndex(seg.index)}
          >
            {/* donutRounded knockout border drawn beneath the colored stroke. */}
            {seg.rounded && geometry.borderWidth > 0 && (
              <path
                d={seg.path}
                fill="none"
                stroke="var(--bg-primary)"
                strokeWidth={seg.strokeWidth + geometry.borderWidth * 2}
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            )}
            <path
              d={seg.path}
              fill={seg.filled ? seg.color : 'none'}
              stroke={seg.filled ? 'none' : seg.color}
              strokeWidth={seg.filled ? 0 : seg.strokeWidth}
              strokeLinecap={seg.rounded ? 'round' : 'butt'}
              strokeLinejoin="round"
            />
          </g>
        ))}
      </svg>

      {/* External badge labels overlay. */}
      <div className="bt-circle-chart__labels">
        {geometry.segments.map((seg) => (
          <div
            key={`badge-${seg.index}`}
            className="bt-circle-chart__badge"
            style={{ left: seg.badge.x, top: seg.badge.y }}
          >
            {seg.badge.label && (
              <span className="bt-circle-chart__badge-label">{seg.badge.label}</span>
            )}
            <span className="bt-circle-chart__badge-value">{seg.badge.pct}</span>
          </div>
        ))}
      </div>

      {/* Floating tooltip — real BTTooltip anchored at the active segment. */}
      {activeSegment && (
        <div
          key={activeIndex}
          className="bt-circle-chart__tip"
          style={{ left: activeSegment.tipX, top: activeSegment.tipY }}
        >
          <BTTooltip text={activeSegment.tooltip} position="top" visible>
            <span className="bt-circle-chart__tip-anchor" aria-hidden="true" />
          </BTTooltip>
        </div>
      )}
    </div>
  );
}

export { BTCircleChart } from './BTCircleChart';
export type { BTCircleChartProps } from './BTCircleChart';
export type { BTCircleSection, BTCircleChartVariant } from './BTCircleChart.types';

// circle-chart.utils.ts — pure geometry for the custom-SVG BTCircleChart.
//
// BTCircleChart is rendered as raw SVG (no ApexCharts) so the web donut can
// mirror the Flutter widget exactly: tap/hover a segment → it pops outward,
// a floating tooltip appears, and a radial leader line connects each segment
// to its external Label + % badge.
//
// All dimensions are expressed as ratios of the Flutter baseline `size = 178`
// (outer radius 70, donut inner 36, donutRounded inner 40, segment gap 4,
// badge offset 30, connector gap 3 + length 10, pop-out 8) so the rendering is
// pixel-identical to Flutter at any `size`.
//
// This file is shared verbatim between the Vue and React packages.

import type { BTCircleSection } from './chart.types';

export type BTCircleChartVariant = 'pie' | 'donut' | 'donutRounded';

/** Flutter baseline the ratios below are derived from. */
const BASE = 178;
/** Outer radius as a fraction of the half-size (70 / 89). */
const OUTER_RATIO = 70 / 89;
/** Center-hole radius as a fraction of the half-size, per variant. */
const INNER_RATIO: Record<BTCircleChartVariant, number> = {
  pie: 0,
  donut: 36 / 89,
  donutRounded: 40 / 89,
};

export interface CircleBadge {
  /** Badge center (label + %). */
  x: number;
  y: number;
  /** Connector line: ring edge → badge. */
  lx1: number;
  ly1: number;
  lx2: number;
  ly2: number;
  label: string;
  pct: string;
}

export interface CircleSegment {
  index: number;
  color: string;
  /** Filled wedge (pie) vs stroked arc (donut / donutRounded). */
  filled: boolean;
  /** SVG path data for the colored shape. */
  path: string;
  /** Stroke width for arcs (ring thickness); 0 for filled wedges. */
  strokeWidth: number;
  /** Rounded line-cap (donutRounded only). */
  rounded: boolean;
  /** Pop-out translation along the segment mid-angle (active state). */
  popDx: number;
  popDy: number;
  /** Anchor point (on the ring, along the mid-angle) for the BTTooltip. */
  tipX: number;
  tipY: number;
  /** Tooltip headline, e.g. "A 40%" or "40%". */
  tooltip: string;
  badge: CircleBadge;
}

export interface CircleGeometry {
  size: number;
  cx: number;
  cy: number;
  outerR: number;
  innerR: number;
  /** Background-colored "knockout" stroke width for donutRounded borders. */
  borderWidth: number;
  segments: CircleSegment[];
}

function polar(cx: number, cy: number, r: number, deg: number) {
  const rad = (deg * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
}

/** Stroked arc along `r` from `a1`→`a2` (deg). Splits a full circle into two. */
function arcPath(cx: number, cy: number, r: number, a1: number, a2: number): string {
  const sweep = a2 - a1;
  if (sweep >= 359.999) {
    const mid = a1 + 180;
    const p0 = polar(cx, cy, r, a1);
    const p1 = polar(cx, cy, r, mid);
    const p2 = polar(cx, cy, r, a2 - 0.001);
    return (
      `M ${p0.x} ${p0.y} A ${r} ${r} 0 1 1 ${p1.x} ${p1.y} ` +
      `A ${r} ${r} 0 1 1 ${p2.x} ${p2.y}`
    );
  }
  const start = polar(cx, cy, r, a1);
  const end = polar(cx, cy, r, a2);
  const largeArc = sweep > 180 ? 1 : 0;
  return `M ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`;
}

/** Filled wedge (pie) from center, `a1`→`a2` (deg). */
function wedgePath(cx: number, cy: number, r: number, a1: number, a2: number): string {
  const sweep = a2 - a1;
  if (sweep >= 359.999) {
    // Full disk — two half-arcs back to start.
    const p0 = polar(cx, cy, r, a1);
    const p1 = polar(cx, cy, r, a1 + 180);
    return (
      `M ${p0.x} ${p0.y} A ${r} ${r} 0 1 1 ${p1.x} ${p1.y} ` +
      `A ${r} ${r} 0 1 1 ${p0.x} ${p0.y} Z`
    );
  }
  const start = polar(cx, cy, r, a1);
  const end = polar(cx, cy, r, a2);
  const largeArc = sweep > 180 ? 1 : 0;
  return (
    `M ${cx} ${cy} L ${start.x} ${start.y} ` +
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y} Z`
  );
}

/**
 * Build all rendering geometry for a circle chart.
 * Angles start at -90° (12 o'clock) and walk clockwise, matching Flutter's
 * `startDegreeOffset: -90`.
 */
export function buildCircleGeometry(
  sections: BTCircleSection[],
  size: number,
  variant: BTCircleChartVariant,
  /**
   * Entrance reveal fraction (0..1). Acts as a single clockwise "hand" that
   * sweeps from 12 o'clock: segment paths are clipped to the cumulative angle
   * `-90° + 360°·reveal`, so the chart draws itself in clockwise (like the
   * Recharts pie). Badge/connector positions stay at their final angle.
   * Defaults to 1 (fully drawn).
   */
  reveal = 1,
): CircleGeometry {
  const half = size / 2;
  const cx = half;
  const cy = half;
  const k = size / BASE; // px scale relative to the Flutter baseline

  const outerR = half * OUTER_RATIO;
  const innerR = half * INNER_RATIO[variant];
  const isPie = variant === 'pie';
  const isRounded = variant === 'donutRounded';

  const strokeWidth = isPie ? 0 : outerR - innerR;
  const midR = (innerR + outerR) / 2;
  // Tooltip anchor radius — on the ring (donut) or 60% out (pie), so the
  // balloon floats just above the touched part of the chart, like Flutter.
  const tipR = isPie ? outerR * 0.6 : midR;
  const borderWidth = isRounded ? 2 * k : 0;

  // Connector + badge offsets (Flutter: gap 3, length 10, badge 30; pop 8).
  const lineR1 = outerR + 3 * k;
  const lineR2 = outerR + 13 * k;
  const badgeR = outerR + 30 * k;
  const pop = 8 * k;

  // donutRounded segment gap (Flutter: 4px at mid-radius), as an angle.
  const gapDeg = isRounded && midR > 0 ? ((4 * k) / midR) * (180 / Math.PI) : 0;

  const total = sections.reduce((s, sec) => s + sec.value, 0);
  if (total <= 0) {
    return { size, cx, cy, outerR, innerR, borderWidth, segments: [] };
  }

  // Clockwise reveal boundary — segments are drawn only up to this angle.
  const revealMax = -90 + 360 * Math.max(0, Math.min(1, reveal));

  let cum = -90;
  const segments: CircleSegment[] = sections.map((sec, index) => {
    const sweep = (sec.value / total) * 360;
    const mid = cum + sweep / 2;
    const midRad = (mid * Math.PI) / 180;

    // Arc endpoints (shrunk by the rounded gap, half on each side).
    const a1 = cum + gapDeg / 2;
    const a2 = cum + sweep - gapDeg / 2;
    cum += sweep;

    // Clip the drawn end to the reveal hand; skip segments not yet reached.
    const drawnEnd = Math.min(a2, revealMax);
    const visible = drawnEnd > a1 + 0.0001;
    const path = !visible
      ? ''
      : isPie
        ? wedgePath(cx, cy, outerR, a1, drawnEnd)
        : arcPath(cx, cy, midR, a1, Math.max(drawnEnd, a1));

    const pct = (sec.value / total) * 100;
    const pctText = `${pct.toFixed(0)}%`;
    const label = sec.label ?? '';
    const tooltip = label ? `${label} ${pctText}` : pctText;

    return {
      index,
      color: sec.color,
      filled: isPie,
      path,
      strokeWidth,
      rounded: isRounded,
      popDx: pop * Math.cos(midRad),
      popDy: pop * Math.sin(midRad),
      tipX: cx + tipR * Math.cos(midRad),
      tipY: cy + tipR * Math.sin(midRad),
      tooltip,
      badge: {
        x: cx + badgeR * Math.cos(midRad),
        y: cy + badgeR * Math.sin(midRad),
        lx1: cx + lineR1 * Math.cos(midRad),
        ly1: cy + lineR1 * Math.sin(midRad),
        lx2: cx + lineR2 * Math.cos(midRad),
        ly2: cy + lineR2 * Math.sin(midRad),
        label,
        pct: pctText,
      },
    };
  });

  return { size, cx, cy, outerR, innerR, borderWidth, segments };
}

// Internal chart types — shared across BTBarChart, BTLineChart, BTCircleChart, BTChartCard.
// Do NOT re-export from component barrels.

/** Single bar datum for BTBarChart basic variant. */
export interface BTBarData {
  value: number;
  /** x-axis label */
  label?: string;
}

/** One rod within a grouped or stacked bar. */
export interface BTBarItem {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One x-position group for BTBarChart grouped variant. */
export interface BTBarGroupData {
  /** x-axis label */
  label?: string;
  bars: BTBarItem[];
}

/** One stacked bar for BTBarChart stacked variant. */
export interface BTStackedBarData {
  /** x-axis label */
  label?: string;
  segments: BTBarItem[];
}

/** One (x, y) data point for BTLineChart. */
export interface BTLineSpot {
  x: number;
  y: number;
}

/** One series for BTLineChart. */
export interface BTLineSeries {
  spots: BTLineSpot[];
  /** CSS color or var(--token) */
  color: string;
  /** Series name shown in tooltip */
  label?: string;
}

/** One section for BTCircleChart. */
export interface BTCircleSection {
  value: number;
  /** CSS color or var(--token) */
  color: string;
  /** Section label shown on badge and in tooltip */
  label?: string;
}

/** Legend item shown in BTChartCard. */
export interface BTChartLegendItem {
  label: string;
  /** CSS color or var(--token) */
  color: string;
}

/** Summary metric shown in BTChartCard header area. */
export interface BTChartSummaryItem {
  label: string;
  value: string;
  unit?: string;
}

/** One row inside the chart tooltip balloon. */
export interface BTChartTooltipItem {
  /** Swatch color */
  color: string;
  /** Series name — empty string hides the label column */
  label: string;
  /** Formatted value string */
  value: string;
}
